# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, id, balance=0):
        self.id = id
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            return False

    def withdrawal(self, amount):
        if 0 < amount <= self.balance:
            self.balance -= amount
            return True
        else:
            return False

def process_transactions(accounts, transactions):
    for transaction in transactions:
        action = transaction[0]
        account_id = transaction[1]
        amount = transaction[2]
        
        # Find the corresponding account object based on its id.
        account = next((acc for acc in accounts if acc.id == account_id), None)

        if action.lower() == 'deposit':
            account.deposit(amount)
        elif action.lower() == 'withdrawal':
            account.withdrawal(amount)